"use strict";(globalThis.webpackChunksite=globalThis.webpackChunksite||[]).push([[961],{6145:(e,i,t)=>{t.r(i),t.d(i,{assets:()=>c,contentTitle:()=>o,default:()=>h,frontMatter:()=>r,metadata:()=>n,toc:()=>l});const n=JSON.parse('{"id":"leios-use-cases","title":"Use cases","description":"Leios aims to increase throughput from approximately 5-10 transactions per second (TPS) to around 100 TPS, with a longer-term target of 1,000 TPS or more, subject to validation and parameter selection. This projected increase in capacity, combined with Cardano\u2019s emphasis on security, predictable fees, and a distributed network of approximately 3,000 stake pools, would expand the range of feasible use cases. The following sections outline five areas where higher throughput could have a meaningful impact.","source":"@site/docs/leios-use-cases.md","sourceDirName":".","slug":"/leios-use-cases","permalink":"/docs/leios-use-cases","draft":false,"unlisted":false,"tags":[],"version":"current","frontMatter":{},"sidebar":"documentationSidebar","previous":{"title":"What is Leios","permalink":"/docs/what-is-leios"},"next":{"title":"Roadmap","permalink":"/docs/roadmap"}}');var a=t(4848),s=t(8453);const r={},o="Use cases",c={},l=[{value:"Global microtransaction ecosystems",id:"global-microtransaction-ecosystems",level:2},{value:"Decentralized supply chain tracking",id:"decentralized-supply-chain-tracking",level:2},{value:"Scalable DeFi with time-sensitive transactions",id:"scalable-defi-with-time-sensitive-transactions",level:2},{value:"Decentralized identity for large populations",id:"decentralized-identity-for-large-populations",level:2},{value:"Real-time voting systems",id:"real-time-voting-systems",level:2},{value:"Why Leios stands out",id:"why-leios-stands-out",level:2},{value:"The road ahead",id:"the-road-ahead",level:2}];function d(e){const i={h1:"h1",h2:"h2",header:"header",li:"li",p:"p",strong:"strong",ul:"ul",...(0,s.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(i.header,{children:(0,a.jsx)(i.h1,{id:"use-cases",children:"Use cases"})}),"\n",(0,a.jsx)(i.p,{children:"Leios aims to increase throughput from approximately 5-10 transactions per second (TPS) to around 100 TPS, with a longer-term target of 1,000 TPS or more, subject to validation and parameter selection. This projected increase in capacity, combined with Cardano\u2019s emphasis on security, predictable fees, and a distributed network of approximately 3,000 stake pools, would expand the range of feasible use cases. The following sections outline five areas where higher throughput could have a meaningful impact."}),"\n",(0,a.jsx)(i.h2,{id:"global-microtransaction-ecosystems",children:"Global microtransaction ecosystems"}),"\n",(0,a.jsx)(i.p,{children:"A higher-throughput network enables low-value, cross-border payments to settle quickly and at predictable cost. Examples include small tips to content creators, machine-to-machine payments such as smart device access, or in-game purchases across regions. Increased capacity makes these use cases more practical at scale."}),"\n",(0,a.jsxs)(i.ul,{children:["\n",(0,a.jsxs)(i.li,{children:[(0,a.jsx)(i.strong,{children:"Why Leios is suitable"})," \u2013 with a projected range of 100\u20131,000 TPS, Leios would support millions of low-value transactions per day. At 100 TPS, this equates to approximately 8.6 million transactions daily. Greater throughput can reduce per-transaction costs and improve fee stability. In addition, partial transaction determinism \u2014 where fees are predictable, with limited variance in rare contention scenarios \u2014 reduces the risk of unexpected costs during periods of high demand."]}),"\n",(0,a.jsxs)(i.li,{children:[(0,a.jsx)(i.strong,{children:"Comparison with other networks"})," \u2013 Bitcoin processes approximately 7 TPS, and transaction fees can range from one to five US dollars during congestion, limiting suitability for microtransactions. Ethereum typically processes 15\u201330 TPS, with fees that fluctuate significantly depending on network demand. Solana advertises substantially higher throughput, but its validator set is more concentrated, which may raise concerns about operational centralization for certain use cases."]}),"\n",(0,a.jsxs)(i.li,{children:[(0,a.jsx)(i.strong,{children:"Real-world vision"})," \u2013 a decentralized streaming platform could enable users to transfer 0.05 ada per view to creators, with transactions processed promptly and without reliance on centralized intermediaries."]}),"\n"]}),"\n",(0,a.jsx)(i.h2,{id:"decentralized-supply-chain-tracking",children:"Decentralized supply chain tracking"}),"\n",(0,a.jsx)(i.p,{children:"Global supply chains require timely, verifiable updates to track goods such as food, medical products, or industrial components. A higher-throughput consensus layer would allow more frequent on-chain recording of events, improving transparency and auditability across jurisdictions."}),"\n",(0,a.jsxs)(i.ul,{children:["\n",(0,a.jsxs)(i.li,{children:[(0,a.jsx)(i.strong,{children:"Why Leios is suitable"})," \u2013 supply chains generate continuous data streams, including Internet of Things (IOT) sensor readings and shipping scans. A throughput range of around 100 TPS would support a significantly higher volume of updates than the current baseline of approximately 10 TPS, reducing the risk of backlog during peak periods. Increased capacity, combined with a distributed network of roughly 3,000 stake pools, strengthens resilience and supports tamper-evident, audit-ready records without reliance on a central authority."]}),"\n",(0,a.jsxs)(i.li,{children:[(0,a.jsx)(i.strong,{children:"Comparison with other networks"})," \u2013 Ethereum can experience high fees and congestion during periods of demand, making frequent state updates costly. Bitcoin has comparatively low throughput, limiting its suitability for near-real-time tracking. Solana offers high throughput, but concerns about validator concentration may affect its suitability in highly regulated or audit-sensitive contexts."]}),"\n",(0,a.jsxs)(i.li,{children:[(0,a.jsx)(i.strong,{children:"Real-world vision"})," \u2013 a pharmaceutical manufacturer records each handoff of a vaccine batch on-chain. Regulators and partners can independently verify the product's full lifecycle against a decentralized, tamper-resistant ledger."]}),"\n"]}),"\n",(0,a.jsx)(i.h2,{id:"scalable-defi-with-time-sensitive-transactions",children:"Scalable DeFi with time-sensitive transactions"}),"\n",(0,a.jsx)(i.p,{children:"Decentralized finance (DeFi) requires timely transaction processing, particularly for liquidations, arbitrage, and collateral adjustments. Higher and more predictable throughput would improve reliability during periods of elevated market activity."}),"\n",(0,a.jsxs)(i.ul,{children:["\n",(0,a.jsxs)(i.li,{children:[(0,a.jsx)(i.strong,{children:"Why Leios is suitable"})," \u2013 increased capacity reduces the likelihood of congestion during demand spikes, supporting time-sensitive operations such as loan liquidations. A projected throughput range of 100\u20131,000 TPS would allow significantly more concurrent activity than the current baseline. Partial transaction determinism supports predictable fees, with limited variance in contention scenarios, reducing the risk of failed or unexpectedly expensive transactions. Cardano\u2019s distributed stake pool model also supports open and non-discriminatory transaction inclusion."]}),"\n",(0,a.jsxs)(i.li,{children:[(0,a.jsx)(i.strong,{children:"Comparison with other networks"})," \u2013 Ethereum has experienced congestion and fee spikes during periods of intense DeFi activity, increasing transaction costs and failure rates. Solana provides high throughput but has a comparatively concentrated validator set. Bitcoin does not natively support general-purpose smart contracts required for most DeFi protocols."]}),"\n",(0,a.jsxs)(i.li,{children:[(0,a.jsx)(i.strong,{children:"Real-world vision"})," \u2013 a decentralized exchange such as SundaeSwap processes a surge in trading activity during market volatility. Orders and liquidations are confirmed within expected time bounds, and fees remain predictable, enabling users to manage risk effectively."]}),"\n"]}),"\n",(0,a.jsx)(i.h2,{id:"decentralized-identity-for-large-populations",children:"Decentralized identity for large populations"}),"\n",(0,a.jsx)(i.p,{children:"Digital identity systems require secure issuance, verification, and revocation of credentials at scale. A higher-throughput consensus layer would better support population-level identity activity, including frequent updates and attestations."}),"\n",(0,a.jsxs)(i.ul,{children:["\n",(0,a.jsxs)(i.li,{children:[(0,a.jsx)(i.strong,{children:"Why Leios is suitable"})," \u2013 A projected capacity of around 100 TPS or more would allow millions of identity-related transactions per day, such as credential issuance and verification, exceeding the current baseline of approximately 10 TPS under Praos. Increased throughput can reduce per-transaction costs, making large-scale deployments more economically viable. Cardano\u2019s decentralized stake pool model also limits reliance on a single controlling entity, which is important for systems handling sensitive identity data. Solutions such as Atala PRISM could benefit from improved scalability at the base layer."]}),"\n",(0,a.jsxs)(i.li,{children:[(0,a.jsx)(i.strong,{children:"Comparison with other networks"})," \u2013 Ethereum may face cost and throughput constraints during periods of high demand. Bitcoin does not natively support the flexible smart contract functionality typically required for decentralized identity frameworks. Solana offers higher throughput but has a more concentrated validator set, which may raise governance and trust considerations in sovereign identity deployments."]}),"\n",(0,a.jsxs)(i.li,{children:[(0,a.jsx)(i.strong,{children:"Real-world vision"})," \u2013 a public authority issues digital credentials to 10 million citizens. Daily verifications for healthcare access or voting eligibility are recorded on-chain, with predictable fees and independently verifiable integrity."]}),"\n"]}),"\n",(0,a.jsx)(i.h2,{id:"real-time-voting-systems",children:"Real-time voting systems"}),"\n",(0,a.jsx)(i.p,{children:"Secure and transparent voting systems require timely transaction processing, verifiable inclusion, and resistance to censorship. Higher throughput at the consensus layer would better support large-scale participation, whether in public elections or on-chain governance processes."}),"\n",(0,a.jsxs)(i.ul,{children:["\n",(0,a.jsxs)(i.li,{children:[(0,a.jsx)(i.strong,{children:"Why Leios is suitable"})," \u2013 a projected capacity of around 100 TPS would allow millions of votes to be recorded per day, significantly increasing the scale supported by the current baseline. Greater throughput reduces the risk of backlogs during periods of high participation. In addition, stake-based mechanisms and endorsement structures are designed to provide verifiable and tamper-evident outcomes, while maintaining censorship resistance under realistic network conditions."]}),"\n",(0,a.jsxs)(i.li,{children:[(0,a.jsx)(i.strong,{children:"Comparison with other networks"})," \u2013 Ethereum may experience congestion during peak demand, affecting transaction finality times and costs. Bitcoin has limited throughput and does not support the flexible smart contract logic required for complex voting systems. Solana provides higher throughput but operates with a comparatively concentrated validator set, which may raise governance considerations in voting contexts."]}),"\n",(0,a.jsxs)(i.li,{children:[(0,a.jsx)(i.strong,{children:"Real-world vision"})," \u2013 delegated representatives (DReps) participate in on-chain governance by casting votes that are recorded and finalized within predictable time bounds. The resulting ledger provides a transparent, independently verifiable record of the decision-making process."]}),"\n"]}),"\n",(0,a.jsx)(i.h2,{id:"why-leios-stands-out",children:"Why Leios stands out"}),"\n",(0,a.jsx)(i.p,{children:"Leios focuses on increasing throughput while preserving reliability and decentralization. A projected range of 100\u20131,000 TPS would allow many applications to operate concurrently with lower risk of congestion than today\u2019s baseline. Elastic capacity is intended to absorb temporary demand spikes, which is relevant for time-sensitive use cases such as decentralized finance and voting."}),"\n",(0,a.jsx)(i.p,{children:"Cardano\u2019s network of approximately 3,000 stake pools supports decentralization at the consensus layer. In addition, partial transaction determinism aims to keep fees largely predictable, with limited variance in contention scenarios. This improves cost transparency for applications such as microtransactions or identity systems, where stable fees are important for usability and planning."}),"\n",(0,a.jsx)(i.p,{children:"Compared with Ethereum and Bitcoin, which face throughput constraints under heavy load, and Solana, which operates with a comparatively concentrated validator set, Leios emphasizes a balance between scale and distributed participation."}),"\n",(0,a.jsx)(i.h2,{id:"the-road-ahead",children:"The road ahead"}),"\n",(0,a.jsx)(i.p,{children:"Leios remains in research and development, with further simulations, prototypes, and public test networks expected before any production deployment. Broader adoption will depend on implementation maturity, ecosystem readiness, and governance approval."}),"\n",(0,a.jsx)(i.p,{children:"Open challenges, including transaction conflicts and adversarial scenarios, are under active analysis. Proposed mitigations include mechanisms such as collateralization and pre-validation approaches to reduce the impact of double-spend attempts or invalid transactions."}),"\n",(0,a.jsx)(i.p,{children:"If adopted through Cardano\u2019s governance processes, Leios would expand the network\u2019s capacity while maintaining its existing security and decentralization principles. Community participation from stake pool operators, delegated representatives, developers, and users will be central to evaluating and refining the proposal."})]})}function h(e={}){const{wrapper:i}={...(0,s.R)(),...e.components};return i?(0,a.jsx)(i,{...e,children:(0,a.jsx)(d,{...e})}):d(e)}},8453:(e,i,t)=>{t.d(i,{R:()=>r,x:()=>o});var n=t(6540);const a={},s=n.createContext(a);function r(e){const i=n.useContext(s);return n.useMemo(function(){return"function"==typeof e?e(i):{...i,...e}},[i,e])}function o(e){let i;return i=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:r(e.components),n.createElement(s.Provider,{value:i},e.children)}}}]);